pub fn record_block_build_attempt(...) {
    if !block_build_trace_enabled() { return; }
    let entry = BlockBuildAttemptTrace { sequence: BLOCK_BUILD_TRACE_SEQUENCE.fetch_add(1, Ordering::Relaxed), ... };
    if guard.len() >= capacity { guard.pop_front(); }
    guard.push_back(entry);
}

